class Tokenizer:
    def __init__(self):
        self.vocab={}
    def fit(self,texts):
        idx=0
        for text in texts:
            for word in text.split():
                if word not in self.vocab:
                    self.vocab[word]=idx; idx+=1
    def transform(self,text):
        return [self.vocab.get(w,-1) for w in text.split()]

t=Tokenizer()
t.fit(['hello world','world peace'])
print(t.transform('hello peace'))
